<div class="es">
<svg viewBox="0 0 700 440" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="30" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Cronología de la Reforma Fiscal y Regulatoria Cripto de Japón</text>
  <text x="20" y="50" fill="#71717a" font-size="13" font-family="sans-serif">Abril de 2026 hasta el objetivo de 2028</text>
  <line x1="40" y1="80" x2="40" y2="360" stroke="#3f3f46" stroke-width="2"/>
  <circle cx="40" cy="90" r="7" fill="#38bdf8"/>
  <text x="60" y="86" fill="#e4e4e7" font-size="14" font-weight="700" font-family="sans-serif">1 abr 2026 — Exención corporativa de ganancias no realizadas</text>
